//! SQL-backed message store (JDBC-equivalent), behind the `sql` feature.

use std::str::FromStr;

use async_trait::async_trait;
use sqlx::sqlite::{SqliteConnectOptions, SqlitePool};
use sqlx::Row;

use crate::{MessageStore, StoreError};

fn backend<E: std::fmt::Display>(e: E) -> StoreError {
    StoreError::Backend(e.to_string())
}

/// A SQL-backed store using `sqlx` (SQLite). Maps the QuickFIX/J JDBC store tables
/// (sequence numbers + sent messages) to a relational schema.
pub struct SqlStore {
    pool: SqlitePool,
}

impl SqlStore {
    /// Connect to `url` (e.g. `sqlite://truefix.db` or `sqlite::memory:`) and ensure the schema.
    pub async fn connect(url: &str) -> Result<Self, StoreError> {
        let opts = SqliteConnectOptions::from_str(url)
            .map_err(backend)?
            .create_if_missing(true);
        let pool = SqlitePool::connect_with(opts).await.map_err(backend)?;

        sqlx::query(
            "CREATE TABLE IF NOT EXISTS seqnums (\
             id INTEGER PRIMARY KEY CHECK (id = 0), sender INTEGER NOT NULL, target INTEGER NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(backend)?;
        sqlx::query("INSERT OR IGNORE INTO seqnums (id, sender, target) VALUES (0, 1, 1)")
            .execute(&pool)
            .await
            .map_err(backend)?;
        sqlx::query(
            "CREATE TABLE IF NOT EXISTS messages (seq INTEGER PRIMARY KEY, data BLOB NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(backend)?;

        Ok(Self { pool })
    }

    async fn get_seq(&self, column: &str) -> Result<u64, StoreError> {
        let sql = format!("SELECT {column} FROM seqnums WHERE id = 0");
        let row = sqlx::query(&sql)
            .fetch_one(&self.pool)
            .await
            .map_err(backend)?;
        let value: i64 = row.try_get(column).map_err(backend)?;
        Ok(value as u64)
    }

    async fn set_seq(&self, column: &str, seq: u64) -> Result<(), StoreError> {
        let sql = format!("UPDATE seqnums SET {column} = ? WHERE id = 0");
        sqlx::query(&sql)
            .bind(seq as i64)
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        Ok(())
    }
}

#[async_trait]
impl MessageStore for SqlStore {
    async fn next_sender_seq(&self) -> Result<u64, StoreError> {
        self.get_seq("sender").await
    }
    async fn next_target_seq(&self) -> Result<u64, StoreError> {
        self.get_seq("target").await
    }
    async fn set_next_sender_seq(&self, seq: u64) -> Result<(), StoreError> {
        self.set_seq("sender", seq).await
    }
    async fn set_next_target_seq(&self, seq: u64) -> Result<(), StoreError> {
        self.set_seq("target", seq).await
    }
    async fn save(&self, seq: u64, message: &[u8]) -> Result<(), StoreError> {
        sqlx::query("INSERT OR REPLACE INTO messages (seq, data) VALUES (?, ?)")
            .bind(seq as i64)
            .bind(message)
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        Ok(())
    }
    async fn get(&self, begin: u64, end: u64) -> Result<Vec<(u64, Vec<u8>)>, StoreError> {
        let rows =
            sqlx::query("SELECT seq, data FROM messages WHERE seq BETWEEN ? AND ? ORDER BY seq")
                .bind(begin as i64)
                .bind(end as i64)
                .fetch_all(&self.pool)
                .await
                .map_err(backend)?;
        let mut out = Vec::with_capacity(rows.len());
        for row in rows {
            let seq: i64 = row.try_get("seq").map_err(backend)?;
            let data: Vec<u8> = row.try_get("data").map_err(backend)?;
            out.push((seq as u64, data));
        }
        Ok(out)
    }
    async fn reset(&self) -> Result<(), StoreError> {
        sqlx::query("DELETE FROM messages")
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        sqlx::query("UPDATE seqnums SET sender = 1, target = 1 WHERE id = 0")
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        Ok(())
    }
}

//! SQL-backed log (JDBC-equivalent), behind the `sql` feature.
//!
//! The [`Log`] trait is synchronous and infallible, while `sqlx` is async. [`SqlLog`] bridges the
//! two: each entry is pushed onto an unbounded channel (a non-blocking, sync send) and written to
//! the database by a background task.

use std::str::FromStr;

use sqlx::sqlite::{SqliteConnectOptions, SqlitePool};
use tokio::sync::mpsc;

use crate::{Log, LogError};

enum Entry {
    Message {
        direction: &'static str,
        text: String,
    },
    Event {
        text: String,
    },
}

/// A SQL-backed log writing to `log_messages` and `log_events` tables via a background task.
pub struct SqlLog {
    tx: mpsc::UnboundedSender<Entry>,
}

impl SqlLog {
    /// Connect to `url` (e.g. `sqlite://truefix-log.db`), ensure the schema, and spawn the writer.
    pub async fn connect(url: &str) -> Result<Self, LogError> {
        let opts = SqliteConnectOptions::from_str(url)
            .map_err(|e| LogError::Io(e.to_string()))?
            .create_if_missing(true);
        let pool = SqlitePool::connect_with(opts)
            .await
            .map_err(|e| LogError::Io(e.to_string()))?;

        sqlx::query(
            "CREATE TABLE IF NOT EXISTS log_messages (id INTEGER PRIMARY KEY AUTOINCREMENT, \
             direction TEXT NOT NULL, text TEXT NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(|e| LogError::Io(e.to_string()))?;
        sqlx::query(
            "CREATE TABLE IF NOT EXISTS log_events (id INTEGER PRIMARY KEY AUTOINCREMENT, \
             text TEXT NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(|e| LogError::Io(e.to_string()))?;

        let (tx, mut rx) = mpsc::unbounded_channel::<Entry>();
        tokio::spawn(async move {
            while let Some(entry) = rx.recv().await {
                match entry {
                    Entry::Message { direction, text } => {
                        let _ =
                            sqlx::query("INSERT INTO log_messages (direction, text) VALUES (?, ?)")
                                .bind(direction)
                                .bind(text)
                                .execute(&pool)
                                .await;
                    }
                    Entry::Event { text } => {
                        let _ = sqlx::query("INSERT INTO log_events (text) VALUES (?)")
                            .bind(text)
                            .execute(&pool)
                            .await;
                    }
                }
            }
        });

        Ok(Self { tx })
    }
}

impl Log for SqlLog {
    fn on_incoming(&self, message: &str) {
        let _ = self.tx.send(Entry::Message {
            direction: "I",
            text: message.to_owned(),
        });
    }
    fn on_outgoing(&self, message: &str) {
        let _ = self.tx.send(Entry::Message {
            direction: "O",
            text: message.to_owned(),
        });
    }
    fn on_event(&self, text: &str) {
        let _ = self.tx.send(Entry::Event {
            text: text.to_owned(),
        });
    }
}

//! Build-time codegen (dual-track, Constitution Principle IV).
//!
//! Reads the same normalized dictionary sources the runtime loads, and generates per-version
//! message-type constants plus a content hash. The runtime asserts its parsed hash equals the
//! generated one, proving codegen and runtime derive from one source.

use std::env;
use std::fmt::Write as _;
use std::fs;
use std::path::Path;

fn fnv1a(bytes: &[u8]) -> u64 {
    let mut hash: u64 = 0xcbf2_9ce4_8422_2325;
    for &b in bytes {
        hash ^= u64::from(b);
        hash = hash.wrapping_mul(0x0000_0100_0000_01b3);
    }
    hash
}

fn main() {
    let manifest = env::var("CARGO_MANIFEST_DIR").expect("CARGO_MANIFEST_DIR");
    let out_dir = env::var("OUT_DIR").expect("OUT_DIR");
    let mut code = String::new();
    code.push_str("// @generated by build.rs from dict-src/normalized — do not edit.\n");

    for (name, file) in [
        ("FIX40", "FIX40.fixdict"),
        ("FIX41", "FIX41.fixdict"),
        ("FIX42", "FIX42.fixdict"),
        ("FIX43", "FIX43.fixdict"),
        ("FIX44", "FIX44.fixdict"),
        ("FIXT11", "FIXT11.fixdict"),
        ("FIX50", "FIX50.fixdict"),
        ("FIX50SP1", "FIX50SP1.fixdict"),
        ("FIX50SP2", "FIX50SP2.fixdict"),
    ] {
        let path = Path::new(&manifest).join("dict-src/normalized").join(file);
        println!("cargo:rerun-if-changed={}", path.display());
        let bytes = fs::read(&path).unwrap_or_else(|e| panic!("read {}: {e}", path.display()));
        let hash = fnv1a(&bytes);
        let _ = writeln!(code, "/// Content hash of the {name} dictionary source.");
        let _ = writeln!(code, "pub const {name}_DICT_HASH: u64 = {hash};");

        let module = name.to_lowercase();
        let _ = writeln!(
            code,
            "/// Generated MsgType constants for the {name} dictionary."
        );
        let _ = writeln!(code, "pub mod {module}_msgs {{");
        for line in String::from_utf8_lossy(&bytes).lines() {
            let line = line.trim();
            if let Some(rest) = line.strip_prefix("message ") {
                let mut it = rest.split_whitespace();
                if let (Some(msg_type), Some(msg_name)) = (it.next(), it.next()) {
                    let ident = msg_name.to_uppercase();
                    let _ = writeln!(code, "    /// MsgType for {msg_name}.");
                    let _ = writeln!(code, "    pub const {ident}: &str = {msg_type:?};");
                }
            }
        }
        let _ = writeln!(code, "}}");
    }

    let dest = Path::new(&out_dir).join("generated.rs");
    fs::write(&dest, code).unwrap_or_else(|e| panic!("write generated.rs: {e}"));
}

//! `truefix-transport` — tokio TCP Initiator and Acceptor that drive a [`Session`].
//!
//! Single- and multi-session initiator/acceptor over TCP or TLS (rustls), framing FIX messages off
//! the stream and pumping the sans-IO [`Session`] engine. Supports routing by SessionID, dynamic
//! sessions, allow-listing, reconnect, optional [`Services`] (persistent [`MessageStore`], [`Log`],
//! socket options, [`Monitor`]), and an operational monitoring surface.
//!
//! Design: `specs/001-fix-engine-parity/`.
#![cfg_attr(
    not(test),
    deny(
        clippy::unwrap_used,
        clippy::expect_used,
        clippy::panic,
        clippy::indexing_slicing
    )
)]

mod framing;

use std::collections::HashMap;
use std::future::pending;
use std::net::{IpAddr, SocketAddr};
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::{Arc, Mutex};
use std::time::Duration;

use tokio::io::{self, AsyncRead, AsyncReadExt, AsyncWrite, AsyncWriteExt};
use tokio::net::{TcpListener, TcpStream};
use tokio::sync::mpsc;
use tokio::task::JoinHandle;
use tokio::time::{interval, MissedTickBehavior};

use truefix_core::{decode, Message};
use truefix_log::Log;
use truefix_session::{
    Action, Application, Event, Schedule, Session, SessionConfig, SessionId, SessionState,
    SessionStatus,
};
use truefix_store::MessageStore;

use framing::frame_length;

/// TCP socket options applied to each connection.
#[derive(Debug, Clone, Copy)]
pub struct SocketOptions {
    /// Disable Nagle's algorithm (TCP_NODELAY).
    pub tcp_no_delay: bool,
}

impl Default for SocketOptions {
    fn default() -> Self {
        Self { tcp_no_delay: true }
    }
}

impl SocketOptions {
    /// Apply the options to a connected stream (best-effort).
    pub fn apply(&self, stream: &TcpStream) {
        let _ = stream.set_nodelay(self.tcp_no_delay);
    }
}

/// Optional per-session services: a persistent message store, a log, and socket options.
#[derive(Clone, Default)]
pub struct Services {
    /// Persistent store for sequence-number continuity (and future cross-restart resend).
    pub store: Option<Arc<dyn MessageStore>>,
    /// Message/event log.
    pub log: Option<Arc<dyn Log>>,
    /// TCP socket options.
    pub socket_options: SocketOptions,
    /// Operational monitor.
    pub monitor: Option<Monitor>,
    /// Optional inbound application-message validator (dictionary + toggles).
    pub validator: Option<(
        truefix_dict::DataDictionary,
        truefix_dict::ValidationOptions,
    )>,
}

/// Control messages to a running session task.
enum Control {
    /// Begin a graceful logout.
    Logout,
    /// Operationally reset the session's sequence numbers and store.
    Reset,
    /// Send an application message on this session.
    Send(Box<Message>),
}

/// Operational monitoring (FR-L): live session status plus reset / force-logout actions
/// (the JMX-equivalent surface).
#[derive(Clone, Default)]
pub struct Monitor {
    inner: Arc<Mutex<HashMap<SessionId, MonitorEntry>>>,
}

struct MonitorEntry {
    status: SessionStatus,
    connected: bool,
    control: mpsc::Sender<Control>,
}

impl Monitor {
    /// Create an empty monitor.
    pub fn new() -> Self {
        Self::default()
    }

    fn register(&self, id: SessionId, status: SessionStatus, control: mpsc::Sender<Control>) {
        if let Ok(mut map) = self.inner.lock() {
            map.insert(
                id,
                MonitorEntry {
                    status,
                    connected: true,
                    control,
                },
            );
        }
    }

    fn update(&self, id: &SessionId, status: SessionStatus) {
        if let Ok(mut map) = self.inner.lock() {
            if let Some(entry) = map.get_mut(id) {
                entry.status = status;
            }
        }
    }

    fn mark_disconnected(&self, id: &SessionId) {
        if let Ok(mut map) = self.inner.lock() {
            if let Some(entry) = map.get_mut(id) {
                entry.connected = false;
            }
        }
    }

    /// The latest status snapshot for `id`.
    pub fn status(&self, id: &SessionId) -> Option<SessionStatus> {
        self.inner.lock().ok()?.get(id).map(|e| e.status)
    }

    /// Whether `id`'s connection is currently up.
    pub fn is_connected(&self, id: &SessionId) -> bool {
        self.inner
            .lock()
            .ok()
            .and_then(|m| m.get(id).map(|e| e.connected))
            .unwrap_or(false)
    }

    /// All known session ids.
    pub fn sessions(&self) -> Vec<SessionId> {
        self.inner
            .lock()
            .map(|m| m.keys().cloned().collect())
            .unwrap_or_default()
    }

    fn control_for(&self, id: &SessionId) -> Option<mpsc::Sender<Control>> {
        self.inner.lock().ok()?.get(id).map(|e| e.control.clone())
    }

    /// Request a graceful logout of `id`.
    pub async fn force_logout(&self, id: &SessionId) -> bool {
        match self.control_for(id) {
            Some(c) => c.send(Control::Logout).await.is_ok(),
            None => false,
        }
    }

    /// Request an operational sequence reset of `id`.
    pub async fn reset(&self, id: &SessionId) -> bool {
        match self.control_for(id) {
            Some(c) => c.send(Control::Reset).await.is_ok(),
            None => false,
        }
    }

    /// Send an application `message` on session `id`. The engine stamps the header
    /// (sequence number, comp IDs, SendingTime).
    pub async fn send_app(&self, id: &SessionId, message: Message) -> bool {
        match self.control_for(id) {
            Some(c) => c.send(Control::Send(Box::new(message))).await.is_ok(),
            None => false,
        }
    }
}

/// A handle to a running session task.
pub struct SessionHandle {
    control: mpsc::Sender<Control>,
    task: JoinHandle<()>,
}

impl SessionHandle {
    /// Request a graceful logout.
    pub async fn logout(&self) {
        let _ = self.control.send(Control::Logout).await;
    }

    /// Send an application message on this session.
    pub async fn send(&self, message: Message) {
        let _ = self.control.send(Control::Send(Box::new(message))).await;
    }

    /// Wait for the session task to finish.
    pub async fn join(self) {
        let _ = self.task.await;
    }
}

/// Connect out as an initiator and run the session.
pub async fn connect_initiator<A>(
    addr: SocketAddr,
    config: SessionConfig,
    app: Arc<A>,
) -> io::Result<SessionHandle>
where
    A: Application + 'static,
{
    connect_initiator_with(addr, config, app, Services::default()).await
}

/// Connect out as an initiator with persistent store/log services.
pub async fn connect_initiator_with<A>(
    addr: SocketAddr,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
) -> io::Result<SessionHandle>
where
    A: Application + 'static,
{
    let stream = TcpStream::connect(addr).await?;
    Ok(spawn_session(stream, config, app, services))
}

/// Connect out as an initiator over TLS (FR-F6).
///
/// `server_name` is the SNI/host name presented to the server (e.g. `"example.com"`).
pub async fn connect_initiator_tls<A>(
    addr: SocketAddr,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
    tls: Arc<rustls::ClientConfig>,
    server_name: rustls::pki_types::ServerName<'static>,
) -> io::Result<SessionHandle>
where
    A: Application + 'static,
{
    let tcp = TcpStream::connect(addr).await?;
    services.socket_options.apply(&tcp);
    let connector = tokio_rustls::TlsConnector::from(tls);
    let stream = connector.connect(server_name, tcp).await?;
    Ok(spawn_session_io(stream, config, app, services))
}

/// A listening acceptor that serves one static session configuration per connection.
pub struct Acceptor<A: Application + 'static> {
    listener: TcpListener,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
}

impl<A: Application + 'static> Acceptor<A> {
    /// Bind to `addr`.
    pub async fn bind(addr: SocketAddr, config: SessionConfig, app: Arc<A>) -> io::Result<Self> {
        Self::bind_with(addr, config, app, Services::default()).await
    }

    /// Bind to `addr` with persistent store/log services.
    pub async fn bind_with(
        addr: SocketAddr,
        config: SessionConfig,
        app: Arc<A>,
        services: Services,
    ) -> io::Result<Self> {
        let listener = TcpListener::bind(addr).await?;
        Ok(Self {
            listener,
            config,
            app,
            services,
        })
    }

    /// The bound local address (useful when binding to port 0).
    pub fn local_addr(&self) -> io::Result<SocketAddr> {
        self.listener.local_addr()
    }

    /// Spawn the accept loop. Each connection is served as a session.
    pub fn serve(self) -> JoinHandle<()> {
        tokio::spawn(async move {
            while let Ok((stream, _peer)) = self.listener.accept().await {
                let _ = spawn_session(
                    stream,
                    self.config.clone(),
                    self.app.clone(),
                    self.services.clone(),
                );
            }
        })
    }
}

fn spawn_session<A>(
    stream: TcpStream,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
) -> SessionHandle
where
    A: Application + 'static,
{
    services.socket_options.apply(&stream);
    spawn_session_io(stream, config, app, services)
}

fn spawn_session_io<A, S>(
    stream: S,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
) -> SessionHandle
where
    A: Application + 'static,
    S: AsyncRead + AsyncWrite + Unpin + Send + 'static,
{
    let (control_tx, control_rx) = mpsc::channel(8);
    let task = {
        let control_tx = control_tx.clone();
        tokio::spawn(async move {
            run_connection(
                stream,
                config,
                app,
                services,
                control_tx,
                control_rx,
                Vec::new(),
            )
            .await;
        })
    };
    SessionHandle {
        control: control_tx,
        task,
    }
}

#[allow(clippy::too_many_arguments)]
async fn run_connection<A, S>(
    mut stream: S,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
    control_tx: mpsc::Sender<Control>,
    mut control: mpsc::Receiver<Control>,
    mut buf: Vec<u8>,
) where
    A: Application + 'static,
    S: AsyncRead + AsyncWrite + Unpin,
{
    let mut session = Session::new(config);
    if let Some((dict, opts)) = &services.validator {
        session.set_dictionary(dict.clone(), *opts);
    }
    let id = session.id().clone();
    app.on_create(&id).await;

    // Restore sequence numbers from the store (continuity across restarts).
    if let Some(store) = &services.store {
        let out = store.next_sender_seq().await.unwrap_or(1);
        let inn = store.next_target_seq().await.unwrap_or(1);
        session.seed_sequences(out, inn);
    }

    if let Some(monitor) = &services.monitor {
        monitor.register(id.clone(), session.status(), control_tx);
    }

    let mut chunk = [0u8; 4096];
    let mut ticker = interval(Duration::from_secs(1));
    ticker.set_missed_tick_behavior(MissedTickBehavior::Delay);

    let mut logged_on = false;
    let mut control_open = true;
    let mut closing = false;

    if dispatch(
        &mut session,
        Event::Connected,
        &mut stream,
        &app,
        &id,
        &services,
        &mut logged_on,
    )
    .await
    .is_err()
    {
        closing = true;
    }

    // Drain any bytes pre-read while routing the connection (acceptor: the inbound Logon).
    if !closing
        && !buf.is_empty()
        && drain_messages(
            &mut buf,
            &mut session,
            &mut stream,
            &app,
            &id,
            &services,
            &mut logged_on,
        )
        .await
        .is_err()
    {
        closing = true;
    }

    while !closing {
        tokio::select! {
            read = stream.read(&mut chunk) => match read {
                Ok(0) | Err(_) => break,
                Ok(n) => {
                    if let Some(slice) = chunk.get(..n) {
                        buf.extend_from_slice(slice);
                    }
                    if drain_messages(&mut buf, &mut session, &mut stream, &app, &id, &services, &mut logged_on)
                        .await
                        .is_err()
                    {
                        closing = true;
                    }
                }
            },
            _ = ticker.tick() => {
                if dispatch(&mut session, Event::Tick, &mut stream, &app, &id, &services, &mut logged_on)
                    .await
                    .is_err()
                {
                    closing = true;
                }
            },
            ctrl = recv_control(&mut control, control_open) => match ctrl {
                Some(Control::Logout) => {
                    if dispatch(&mut session, Event::StartLogout, &mut stream, &app, &id, &services, &mut logged_on)
                        .await
                        .is_err()
                    {
                        closing = true;
                    }
                }
                Some(Control::Reset) => {
                    session.reset();
                    if let Some(store) = &services.store {
                        let _ = store.reset().await;
                    }
                    if let Some(monitor) = &services.monitor {
                        monitor.update(&id, session.status());
                    }
                }
                Some(Control::Send(msg)) => {
                    if send_app(&mut session, *msg, &mut stream, &app, &id, &services)
                        .await
                        .is_err()
                    {
                        closing = true;
                    }
                }
                None => control_open = false,
            },
        }
    }

    let _ = stream.shutdown().await;
    if let Some(monitor) = &services.monitor {
        monitor.mark_disconnected(&id);
    }
    if logged_on {
        app.on_logout(&id).await;
        if let Some(log) = &services.log {
            log.on_event(&format!("{id}: logout"));
        }
    }
}

/// Await a control message, or never resolve once the channel is closed (avoids a busy loop).
async fn recv_control(control: &mut mpsc::Receiver<Control>, open: bool) -> Option<Control> {
    if open {
        control.recv().await
    } else {
        pending::<Option<Control>>().await
    }
}

#[allow(clippy::too_many_arguments)]
async fn drain_messages<A, S>(
    buf: &mut Vec<u8>,
    session: &mut Session,
    stream: &mut S,
    app: &Arc<A>,
    id: &SessionId,
    services: &Services,
    logged_on: &mut bool,
) -> Result<(), ()>
where
    A: Application + 'static,
    S: AsyncRead + AsyncWrite + Unpin,
{
    loop {
        match frame_length(buf) {
            Ok(Some(total)) => {
                let raw: Vec<u8> = buf.drain(..total).collect();
                if let Ok(msg) = decode(&raw) {
                    if let Some(log) = &services.log {
                        log.on_incoming(&String::from_utf8_lossy(&raw));
                    }
                    // Authentication / admin acceptance: an admin message the application rejects
                    // (e.g. a Logon with bad credentials) tears the session down without a response.
                    if is_admin(&msg) {
                        if app.from_admin(&msg, id).await.is_err() {
                            if let Some(log) = &services.log {
                                log.on_event(&format!(
                                    "{id}: admin message rejected by application"
                                ));
                            }
                            return Err(());
                        }
                    } else {
                        // Business rejects are produced by the dictionary hook; deliver regardless.
                        let _ = app.from_app(&msg, id).await;
                    }
                    dispatch(
                        session,
                        Event::Received(msg),
                        stream,
                        app,
                        id,
                        services,
                        logged_on,
                    )
                    .await?;
                }
                // Garbled frames are dropped at this stage; RejectGarbledMessage arrives in S3.
            }
            Ok(None) => return Ok(()),
            Err(_) => {
                buf.clear();
                return Ok(());
            }
        }
    }
}

/// Run the engine for one event and perform the resulting actions. Returns `Err` if the
/// session should be torn down.
#[allow(clippy::too_many_arguments)]
async fn dispatch<A, S>(
    session: &mut Session,
    event: Event,
    stream: &mut S,
    app: &Arc<A>,
    id: &SessionId,
    services: &Services,
    logged_on: &mut bool,
) -> Result<(), ()>
where
    A: Application + 'static,
    S: AsyncWrite + Unpin,
{
    let actions = session.handle(event);

    if !*logged_on && session.is_logged_on() {
        *logged_on = true;
        app.on_logon(id).await;
        if let Some(log) = &services.log {
            log.on_event(&format!("{id}: logon"));
        }
    }

    let mut disconnect = false;
    for action in actions {
        match action {
            Action::Send(mut msg) => {
                if is_admin(&msg) {
                    app.to_admin(&mut msg, id).await;
                } else {
                    app.to_app(&mut msg, id).await;
                }
                let bytes = msg.encode();
                if let Some(log) = &services.log {
                    log.on_outgoing(&String::from_utf8_lossy(&bytes));
                }
                if stream.write_all(&bytes).await.is_err() {
                    return Err(());
                }
            }
            Action::Disconnect => disconnect = true,
        }
    }
    let _ = stream.flush().await;

    // Persist sequence numbers for restart continuity (best-effort).
    if let Some(store) = &services.store {
        let _ = store.set_next_sender_seq(session.next_out_seq()).await;
        let _ = store.set_next_target_seq(session.next_in_seq()).await;
    }

    if let Some(monitor) = &services.monitor {
        monitor.update(id, session.status());
    }

    if disconnect || session.state() == SessionState::Disconnected {
        Err(())
    } else {
        Ok(())
    }
}

fn is_admin(msg: &Message) -> bool {
    matches!(
        msg.msg_type(),
        Some("0" | "1" | "2" | "3" | "4" | "5" | "A")
    )
}

/// Send an application message initiated by the application (via the control channel).
async fn send_app<A, S>(
    session: &mut Session,
    message: Message,
    stream: &mut S,
    app: &Arc<A>,
    id: &SessionId,
    services: &Services,
) -> Result<(), ()>
where
    A: Application + 'static,
    S: AsyncWrite + Unpin,
{
    for action in session.send_app(message) {
        if let Action::Send(mut msg) = action {
            app.to_app(&mut msg, id).await;
            let bytes = msg.encode();
            if let Some(log) = &services.log {
                log.on_outgoing(&String::from_utf8_lossy(&bytes));
            }
            if stream.write_all(&bytes).await.is_err() {
                return Err(());
            }
        }
    }
    let _ = stream.flush().await;
    if let Some(store) = &services.store {
        let _ = store.set_next_sender_seq(session.next_out_seq()).await;
    }
    if let Some(monitor) = &services.monitor {
        monitor.update(id, session.status());
    }
    Ok(())
}

// ===========================================================================================
// Multi-session acceptor (routing by SessionID), dynamic sessions, and allow-listing (S6).
// ===========================================================================================

struct Registry {
    sessions: HashMap<SessionId, SessionConfig>,
    template: Option<SessionConfig>,
    allowed_remotes: Option<Vec<IpAddr>>,
}

/// Builds and serves a multi-session acceptor with optional dynamic sessions and allow-listing.
pub struct AcceptorBuilder<A: Application + 'static> {
    listener: TcpListener,
    app: Arc<A>,
    sessions: HashMap<SessionId, SessionConfig>,
    template: Option<SessionConfig>,
    allowed_remotes: Option<Vec<IpAddr>>,
    services: Services,
    tls: Option<Arc<rustls::ServerConfig>>,
}

impl<A: Application + 'static> AcceptorBuilder<A> {
    /// Bind a multi-session acceptor.
    pub async fn bind(addr: SocketAddr, app: Arc<A>) -> io::Result<Self> {
        let listener = TcpListener::bind(addr).await?;
        Ok(Self {
            listener,
            app,
            sessions: HashMap::new(),
            template: None,
            allowed_remotes: None,
            services: Services::default(),
            tls: None,
        })
    }

    /// Terminate TLS on each accepted connection using `config` (FR-F6).
    #[must_use]
    pub fn with_tls(mut self, config: Arc<rustls::ServerConfig>) -> Self {
        self.tls = Some(config);
        self
    }

    /// The bound local address.
    pub fn local_addr(&self) -> io::Result<SocketAddr> {
        self.listener.local_addr()
    }

    /// Register a static session (keyed by its SessionID).
    #[must_use]
    pub fn with_session(mut self, config: SessionConfig) -> Self {
        self.sessions.insert(config.session_id(), config);
        self
    }

    /// Set a dynamic-session template: connections that don't match a static session are accepted
    /// using this template (AcceptorTemplate / DynamicSession).
    #[must_use]
    pub fn with_dynamic_template(mut self, template: SessionConfig) -> Self {
        self.template = Some(template);
        self
    }

    /// Only accept connections from these remote IP addresses (AllowedRemoteAddresses).
    #[must_use]
    pub fn allow_remotes(mut self, ips: Vec<IpAddr>) -> Self {
        self.allowed_remotes = Some(ips);
        self
    }

    /// Attach store/log/socket services.
    #[must_use]
    pub fn with_services(mut self, services: Services) -> Self {
        self.services = services;
        self
    }

    /// Spawn the accept loop.
    pub fn serve(self) -> JoinHandle<()> {
        let registry = Arc::new(Registry {
            sessions: self.sessions,
            template: self.template,
            allowed_remotes: self.allowed_remotes,
        });
        let app = self.app;
        let services = self.services;
        let listener = self.listener;
        let tls = self.tls.map(tokio_rustls::TlsAcceptor::from);
        tokio::spawn(async move {
            while let Ok((stream, peer)) = listener.accept().await {
                if let Some(allowed) = &registry.allowed_remotes {
                    if !allowed.contains(&peer.ip()) {
                        continue; // refuse: not in the allow-list
                    }
                }
                services.socket_options.apply(&stream);
                let registry = registry.clone();
                let app = app.clone();
                let services = services.clone();
                match &tls {
                    Some(acceptor) => {
                        let acceptor = acceptor.clone();
                        tokio::spawn(async move {
                            if let Ok(tls_stream) = acceptor.accept(stream).await {
                                route_and_run(tls_stream, app, registry, services).await;
                            }
                        });
                    }
                    None => {
                        tokio::spawn(async move {
                            route_and_run(stream, app, registry, services).await;
                        });
                    }
                }
            }
        })
    }
}

async fn route_and_run<A, S>(
    mut stream: S,
    app: Arc<A>,
    registry: Arc<Registry>,
    services: Services,
) where
    A: Application + 'static,
    S: AsyncRead + AsyncWrite + Unpin + Send + 'static,
{
    // Read until the first complete message (the Logon) so we can route by SessionID.
    let mut buf: Vec<u8> = Vec::new();
    let mut chunk = [0u8; 4096];
    let logon = loop {
        match stream.read(&mut chunk).await {
            Ok(0) | Err(_) => return,
            Ok(n) => {
                if let Some(slice) = chunk.get(..n) {
                    buf.extend_from_slice(slice);
                }
            }
        }
        match frame_length(&buf) {
            Ok(Some(total)) => match buf.get(..total).map(decode) {
                Some(Ok(msg)) => break msg,
                _ => return,
            },
            Ok(None) => continue,
            Err(_) => return,
        }
    };

    let begin = logon.begin_string().unwrap_or_default().to_owned();
    let their_sender = field_str(&logon, 49);
    let their_target = field_str(&logon, 56);
    // Our SessionID reverses the counterparty's comp IDs.
    let sid = SessionId::new(begin.clone(), their_target.clone(), their_sender.clone());

    let config = registry.sessions.get(&sid).cloned().or_else(|| {
        registry
            .template
            .as_ref()
            .map(|t| dynamic_config(t, &begin, &their_target, &their_sender))
    });
    let Some(config) = config else {
        return; // no static match and no template -> refuse
    };

    let (control_tx, control_rx) = mpsc::channel(8);
    run_connection(stream, config, app, services, control_tx, control_rx, buf).await;
}

fn field_str(msg: &Message, tag: u32) -> String {
    msg.header
        .get(tag)
        .and_then(|f| f.as_str().ok())
        .unwrap_or_default()
        .to_owned()
}

fn dynamic_config(
    template: &SessionConfig,
    begin: &str,
    our_sender: &str,
    our_target: &str,
) -> SessionConfig {
    let mut config = template.clone();
    config.begin_string = begin.to_owned();
    config.sender_comp_id = our_sender.to_owned();
    config.target_comp_id = our_target.to_owned();
    config
}

// ===========================================================================================
// Reconnecting initiator (S6).
// ===========================================================================================

/// Handle to a reconnecting initiator loop.
pub struct ReconnectHandle {
    stop: Arc<AtomicBool>,
    task: JoinHandle<()>,
}

impl ReconnectHandle {
    /// Signal the loop to stop after the current attempt.
    pub fn stop(&self) {
        self.stop.store(true, Ordering::SeqCst);
    }

    /// Wait for the loop to finish.
    pub async fn join(self) {
        let _ = self.task.await;
    }
}

/// Connect out as an initiator, automatically reconnecting after `config.reconnect_interval`
/// seconds whenever the connection drops, until stopped.
pub fn connect_initiator_reconnecting<A>(
    addr: SocketAddr,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
) -> ReconnectHandle
where
    A: Application + 'static,
{
    let stop = Arc::new(AtomicBool::new(false));
    let loop_stop = stop.clone();
    let interval = Duration::from_secs(u64::from(config.reconnect_interval).max(1));
    let task = tokio::spawn(async move {
        while !loop_stop.load(Ordering::SeqCst) {
            if let Ok(stream) = TcpStream::connect(addr).await {
                let (control_tx, control_rx) = mpsc::channel(8);
                run_connection(
                    stream,
                    config.clone(),
                    app.clone(),
                    services.clone(),
                    control_tx,
                    control_rx,
                    Vec::new(),
                )
                .await;
            }
            if loop_stop.load(Ordering::SeqCst) {
                break;
            }
            tokio::time::sleep(interval).await;
        }
    });
    ReconnectHandle { stop, task }
}

// ===========================================================================================
// Scheduled initiator (S6 schedule wiring): connect only while in session (FR-E1/E2/E3).
// ===========================================================================================

/// Handle to a scheduled initiator loop.
pub struct ScheduledHandle {
    stop: Arc<AtomicBool>,
    task: JoinHandle<()>,
}

impl ScheduledHandle {
    /// Signal the loop to stop after the current check.
    pub fn stop(&self) {
        self.stop.store(true, Ordering::SeqCst);
    }

    /// Wait for the loop to finish.
    pub async fn join(self) {
        let _ = self.task.await;
    }
}

/// Run an initiator that connects only while the `schedule` is in session. On each transition
/// into a session window the store is reset (disconnect → reset sequence numbers → clear store →
/// reconnect, FR-E3); on a transition out of the window the session is logged out.
pub fn run_scheduled_initiator<A>(
    addr: SocketAddr,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
    schedule: Schedule,
) -> ScheduledHandle
where
    A: Application + 'static,
{
    let stop = Arc::new(AtomicBool::new(false));
    let loop_stop = stop.clone();
    let task = tokio::spawn(async move {
        let mut current: Option<SessionHandle> = None;
        let mut was_in_session = false;
        while !loop_stop.load(Ordering::SeqCst) {
            let in_session = schedule.is_in_session(time::OffsetDateTime::now_utc());
            match (in_session, current.is_some()) {
                (true, false) => {
                    if !was_in_session {
                        // Entering a session window: reset persisted state.
                        if let Some(store) = &services.store {
                            let _ = store.reset().await;
                        }
                    }
                    if let Ok(handle) =
                        connect_initiator_with(addr, config.clone(), app.clone(), services.clone())
                            .await
                    {
                        current = Some(handle);
                    }
                }
                (false, true) => {
                    if let Some(handle) = current.take() {
                        handle.logout().await;
                    }
                }
                _ => {}
            }
            was_in_session = in_session;
            tokio::time::sleep(Duration::from_millis(200)).await;
        }
        if let Some(handle) = current.take() {
            handle.logout().await;
        }
    });
    ScheduledHandle { stop, task }
}

//! Authored acceptance-test scenarios (black-box behaviour contracts).
//!
//! These reproduce the *behaviour* of the classic QuickFIX server AT scenarios from the FIX
//! specification — independently scripted, with no source or test data copied (Constitution
//! Principle III). This is a representative core subset (logon, sequence handling, test request,
//! logout); porting the full 73-scenario corpus is incremental authoring on top of this runner.

use truefix_core::{Field, Message};

use crate::runner::{client_message, ExpectMsg, Scenario, Step};

/// The FIX versions the server suite is exercised against.
pub const SUITE_VERSIONS: &[&str] = &["FIX.4.2", "FIX.4.4"];

fn logon(version: &str, seq: i64, reset: bool) -> Message {
    let mut m = client_message(version, "A", seq);
    m.body.set(Field::int(98, 0));
    m.body.set(Field::int(108, 30));
    if reset {
        m.body.set(Field::string(141, "Y"));
    }
    m
}

fn scenario(name: &str, version: &str, steps: Vec<Step>) -> Scenario {
    Scenario {
        name: name.to_owned(),
        versions: vec![version.to_owned()],
        steps,
    }
}

/// 1a — a valid Logon with the correct MsgSeqNum is answered with a Logon.
fn valid_logon(v: &str) -> Scenario {
    scenario(
        "1a_ValidLogonWithCorrectMsgSeqNum",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
        ],
    )
}

/// 1a — a Logon whose MsgSeqNum is too high logs on, then a ResendRequest is issued.
fn logon_seq_too_high(v: &str) -> Scenario {
    scenario(
        "1a_ValidLogonMsgSeqNumTooHigh",
        v,
        vec![
            Step::Send(logon(v, 10, false)), // no reset; expected is 1
            Step::Expect(ExpectMsg::of("A")),
            Step::Expect(ExpectMsg::of("2").field(7, "1")), // ResendRequest BeginSeqNo=1
        ],
    )
}

/// 2b — an application/admin message with MsgSeqNum too high triggers a ResendRequest.
fn msgseqnum_too_high(v: &str) -> Scenario {
    scenario(
        "2b_MsgSeqNumTooHigh",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
            Step::Send(client_message(v, "0", 10)), // Heartbeat, seq too high
            Step::Expect(ExpectMsg::of("2").field(7, "2")), // ResendRequest BeginSeqNo=2
        ],
    )
}

/// 2c — a message with MsgSeqNum too low (no PossDup) draws a Logout and disconnect.
fn msgseqnum_too_low(v: &str) -> Scenario {
    scenario(
        "2c_MsgSeqNumTooLow",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
            Step::Send(client_message(v, "0", 1)), // Heartbeat, seq too low
            Step::Expect(ExpectMsg::of("5")),      // Logout
            Step::ExpectDisconnect,
        ],
    )
}

/// 4b — a received TestRequest is answered with a Heartbeat echoing the TestReqID.
fn received_test_request(v: &str) -> Scenario {
    let mut tr = client_message(v, "1", 2);
    tr.body.set(Field::string(112, "HELLO"));
    scenario(
        "4b_ReceivedTestRequest",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
            Step::Send(tr),
            Step::Expect(ExpectMsg::of("0").field(112, "HELLO")),
        ],
    )
}

/// 13b — an unsolicited Logout is answered with a Logout and disconnect.
fn unsolicited_logout(v: &str) -> Scenario {
    scenario(
        "13b_UnsolicitedLogoutMessage",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
            Step::Send(client_message(v, "5", 2)), // Logout
            Step::Expect(ExpectMsg::of("5")),
            Step::ExpectDisconnect,
        ],
    )
}

/// The (representative) server acceptance-test suite across [`SUITE_VERSIONS`].
pub fn server_suite() -> Vec<Scenario> {
    let mut out = Vec::new();
    for &v in SUITE_VERSIONS {
        out.push(valid_logon(v));
        out.push(logon_seq_too_high(v));
        out.push(msgseqnum_too_high(v));
        out.push(msgseqnum_too_low(v));
        out.push(received_test_request(v));
        out.push(unsolicited_logout(v));
    }
    out
}

//! SQL-backed message store (JDBC-equivalent), behind the `sql` feature.

use std::str::FromStr;

use async_trait::async_trait;
use sqlx::sqlite::{SqliteConnectOptions, SqlitePool};
use sqlx::Row;

use crate::{MessageStore, StoreError};

fn backend<E: std::fmt::Display>(e: E) -> StoreError {
    StoreError::Backend(e.to_string())
}

/// A SQL-backed store using `sqlx` (SQLite). Maps the QuickFIX/J JDBC store tables
/// (sequence numbers + sent messages) to a relational schema.
pub struct SqlStore {
    pool: SqlitePool,
}

impl SqlStore {
    /// Connect to `url` (e.g. `sqlite://truefix.db` or `sqlite::memory:`) and ensure the schema.
    pub async fn connect(url: &str) -> Result<Self, StoreError> {
        let opts = SqliteConnectOptions::from_str(url)
            .map_err(backend)?
            .create_if_missing(true);
        let pool = SqlitePool::connect_with(opts).await.map_err(backend)?;

        sqlx::query(
            "CREATE TABLE IF NOT EXISTS seqnums (\
             id INTEGER PRIMARY KEY CHECK (id = 0), sender INTEGER NOT NULL, target INTEGER NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(backend)?;
        sqlx::query("INSERT OR IGNORE INTO seqnums (id, sender, target) VALUES (0, 1, 1)")
            .execute(&pool)
            .await
            .map_err(backend)?;
        sqlx::query(
            "CREATE TABLE IF NOT EXISTS messages (seq INTEGER PRIMARY KEY, data BLOB NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(backend)?;

        Ok(Self { pool })
    }

    async fn get_seq(&self, column: &str) -> Result<u64, StoreError> {
        let sql = format!("SELECT {column} FROM seqnums WHERE id = 0");
        let row = sqlx::query(&sql)
            .fetch_one(&self.pool)
            .await
            .map_err(backend)?;
        let value: i64 = row.try_get(column).map_err(backend)?;
        Ok(value as u64)
    }

    async fn set_seq(&self, column: &str, seq: u64) -> Result<(), StoreError> {
        let sql = format!("UPDATE seqnums SET {column} = ? WHERE id = 0");
        sqlx::query(&sql)
            .bind(seq as i64)
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        Ok(())
    }
}

#[async_trait]
impl MessageStore for SqlStore {
    async fn next_sender_seq(&self) -> Result<u64, StoreError> {
        self.get_seq("sender").await
    }
    async fn next_target_seq(&self) -> Result<u64, StoreError> {
        self.get_seq("target").await
    }
    async fn set_next_sender_seq(&self, seq: u64) -> Result<(), StoreError> {
        self.set_seq("sender", seq).await
    }
    async fn set_next_target_seq(&self, seq: u64) -> Result<(), StoreError> {
        self.set_seq("target", seq).await
    }
    async fn save(&self, seq: u64, message: &[u8]) -> Result<(), StoreError> {
        sqlx::query("INSERT OR REPLACE INTO messages (seq, data) VALUES (?, ?)")
            .bind(seq as i64)
            .bind(message)
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        Ok(())
    }
    async fn get(&self, begin: u64, end: u64) -> Result<Vec<(u64, Vec<u8>)>, StoreError> {
        let rows =
            sqlx::query("SELECT seq, data FROM messages WHERE seq BETWEEN ? AND ? ORDER BY seq")
                .bind(begin as i64)
                .bind(end as i64)
                .fetch_all(&self.pool)
                .await
                .map_err(backend)?;
        let mut out = Vec::with_capacity(rows.len());
        for row in rows {
            let seq: i64 = row.try_get("seq").map_err(backend)?;
            let data: Vec<u8> = row.try_get("data").map_err(backend)?;
            out.push((seq as u64, data));
        }
        Ok(out)
    }
    async fn reset(&self) -> Result<(), StoreError> {
        sqlx::query("DELETE FROM messages")
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        sqlx::query("UPDATE seqnums SET sender = 1, target = 1 WHERE id = 0")
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        Ok(())
    }
}

//! SQL-backed log (JDBC-equivalent), behind the `sql` feature.
//!
//! The [`Log`] trait is synchronous and infallible, while `sqlx` is async. [`SqlLog`] bridges the
//! two: each entry is pushed onto an unbounded channel (a non-blocking, sync send) and written to
//! the database by a background task.

use std::str::FromStr;

use sqlx::sqlite::{SqliteConnectOptions, SqlitePool};
use tokio::sync::mpsc;

use crate::{Log, LogError};

enum Entry {
    Message {
        direction: &'static str,
        text: String,
    },
    Event {
        text: String,
    },
}

/// A SQL-backed log writing to `log_messages` and `log_events` tables via a background task.
pub struct SqlLog {
    tx: mpsc::UnboundedSender<Entry>,
}

impl SqlLog {
    /// Connect to `url` (e.g. `sqlite://truefix-log.db`), ensure the schema, and spawn the writer.
    pub async fn connect(url: &str) -> Result<Self, LogError> {
        let opts = SqliteConnectOptions::from_str(url)
            .map_err(|e| LogError::Io(e.to_string()))?
            .create_if_missing(true);
        let pool = SqlitePool::connect_with(opts)
            .await
            .map_err(|e| LogError::Io(e.to_string()))?;

        sqlx::query(
            "CREATE TABLE IF NOT EXISTS log_messages (id INTEGER PRIMARY KEY AUTOINCREMENT, \
             direction TEXT NOT NULL, text TEXT NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(|e| LogError::Io(e.to_string()))?;
        sqlx::query(
            "CREATE TABLE IF NOT EXISTS log_events (id INTEGER PRIMARY KEY AUTOINCREMENT, \
             text TEXT NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(|e| LogError::Io(e.to_string()))?;

        let (tx, mut rx) = mpsc::unbounded_channel::<Entry>();
